var surah072 = {
  number: 72,
  nameArabic: "al-Jinn",
  nameEnglish: "Al-Jinn",
  meaning: "The Jinn",
  totalAyahs: 28,
  ayahs: [
    { number: 1, arabic: "قُلْ أُوحِىَ إِلَىَّ أَنَّهُ ٱسْتَمَعَ نَفَرٌۭ مِّنَ ٱلْجِنِّ فَقَالُوٓا۟ إِنَّا سَمِعْنَا قُرْءَانًا عَجَبًۭا", transliteration: "Qul oohiya ilayya annahu istamaAAa nafarun mina aljinni faqaloo inna samiAAna quranan AAajaban", transliterationB: "Qul oohiya ilaiya annna hustama'a nafarum minal jinnni faqaalooo innaa sami'naa quraanan 'ajabaa", english: "Say: It has been revealed to me that a company of Jinns listened (to the Qur'an). They said, 'We have really heard a wonderful Recital", romanUrdu: "Aey Nabi, kaho, meri taraf wahee (revelation) bheji gayi hai ke Jinno ke ek giroh (group) ne gaur se suna phir (jaa kar apne qaum ke logon se) kaha: “humne ek bada hi ajeeb Quran suna hai" },
    { number: 2, arabic: "يَهْدِىٓ إِلَى ٱلرُّشْدِ فَـَٔامَنَّا بِهِۦ ۖ وَلَن نُّشْرِكَ بِرَبِّنَآ أَحَدًۭا", transliteration: "Yahdee ila alrrushdi faamanna bihi walan nushrika birabbina ahadan", transliterationB: "Yahdeee ilar rushdi fa aamannaa bihee wa lan nushrika bi rabbinaaa ahadaa", english: "It gives guidance to the Right, and we have believed therein: we shall not join (in worship) any (gods) with our Lord", romanUrdu: "Jo raah-e-raast ki taraf rehnumayi karta hai is liye hum uspar iman le aaye hain aur ab hum hargiz apne Rubb ke saath kisi ko sharik nahin karenge" },
    { number: 3, arabic: "وَأَنَّهُۥ تَعَٰلَىٰ جَدُّ رَبِّنَا مَا ٱتَّخَذَ صَٰحِبَةًۭ وَلَا وَلَدًۭا", transliteration: "Waannahu taAAala jaddu rabbina ma ittakhatha sahibatan wala waladan", transliterationB: "Wa annahoo Ta'aalaa jaddu Rabbinaa mat takhaza saahibatanw wa la waladaa", english: "And Exalted is the Majesty of our Lord: He has taken neither a wife nor a son", romanUrdu: "Aur yeh ke hamare Rubb ki shaan bahut aala-o-Arfa hai , usne kisi ko biwi ya beta nahin banaya" },
    { number: 4, arabic: "وَأَنَّهُۥ كَانَ يَقُولُ سَفِيهُنَا عَلَى ٱللَّهِ شَطَطًۭا", transliteration: "Waannahu kana yaqoolu safeehuna AAala Allahi shatatan", transliterationB: "Wa annahoo kaana yaqoolu safeehunaa 'alal laahi shatataa", english: "There were some foolish ones among us, who used to utter extravagant lies against Allah", romanUrdu: "Aur yeh ke hamare nadaan log Allah ke barey mein bahut khilaf-e-haqq baatein karte rahey hain" },
    { number: 5, arabic: "وَأَنَّا ظَنَنَّآ أَن لَّن تَقُولَ ٱلْإِنسُ وَٱلْجِنُّ عَلَى ٱللَّهِ كَذِبًۭا", transliteration: "Waanna thananna an lan taqoola alinsu waaljinnu AAala Allahi kathiban", transliterationB: "Wa annaa zanannaaa al lan taqoolal insu wal jinnu 'alal laahi kazibaa", english: "But we do think that no man or spirit should say aught that untrue against Allah", romanUrdu: "Aur yeh ke humne samjha tha ke insaan aur jinn kabhi khuda ke baarey mein jhoot nahin bol sakte" },
    { number: 6, arabic: "وَأَنَّهُۥ كَانَ رِجَالٌۭ مِّنَ ٱلْإِنسِ يَعُوذُونَ بِرِجَالٍۢ مِّنَ ٱلْجِنِّ فَزَادُوهُمْ رَهَقًۭا", transliteration: "Waannahu kana rijalun mina alinsi yaAAoothoona birijalin mina aljinni fazadoohum rahaqan", transliterationB: "Wa annahoo kaana rijaa lum minal insi ya'oozoona birijaalim minal jinni fazaa doohum rahaqaa", english: "True, there were persons among mankind who took shelter with persons among the Jinns, but they increased them in folly", romanUrdu: "Aur yeh ke Insano mein se kuch log Jinno mein se kuch logon ki panaah (refuge) maanga karte thay, is tarah unhon ne Jinno ka guroor aur zyada badha diya" },
    { number: 7, arabic: "وَأَنَّهُمْ ظَنُّوا۟ كَمَا ظَنَنتُمْ أَن لَّن يَبْعَثَ ٱللَّهُ أَحَدًۭا", transliteration: "Waannahum thannoo kama thanantum an lan yabAAatha Allahu ahadan", transliterationB: "Wa annahum zannoo kamaa zanantum al lany yab'asal laahu ahadaa", english: "And they (came to) think as ye thought, that Allah would not raise up any one (to Judgment)", romanUrdu: "Aur yeh ke insaano ne bhi wahi gumaan kiya jaisa tumhara gumaan tha ke Allah kisi ko Rasool bana kar na bhejega" },
    { number: 8, arabic: "وَأَنَّا لَمَسْنَا ٱلسَّمَآءَ فَوَجَدْنَٰهَا مُلِئَتْ حَرَسًۭا شَدِيدًۭا وَشُهُبًۭا", transliteration: "Waanna lamasna alssamaa fawajadnaha muliat harasan shadeedan washuhuban", transliterationB: "Wa annaa lamasnas sa maaa'a fa wajadnaahaa muli'at harasan shadeedanw wa shuhubaa", english: "And we pried into the secrets of heaven; but we found it filled with stern guards and flaming fires", romanUrdu: "Aur yeh ke humne aasman ko tatola to dekha ke woh pehray-daaron (terrible guards) se patha pada hai aur shahabon (shooting meteors) ki baarish ho rahi hai" },
    { number: 9, arabic: "وَأَنَّا كُنَّا نَقْعُدُ مِنْهَا مَقَٰعِدَ لِلسَّمْعِ ۖ فَمَن يَسْتَمِعِ ٱلْءَانَ يَجِدْ لَهُۥ شِهَابًۭا رَّصَدًۭا", transliteration: "Waanna kunna naqAAudu minha maqaAAida lilssamAAi faman yastamiAAi alana yajid lahu shihaban rasadan", transliterationB: "Wa annaa kunnaa naq'udu minhaa maqaa'ida lis'sam'i famany yastami'il aana yajid lahoo shihaabar rasada", english: "We used, indeed, to sit there in (hidden) stations, to (steal) a hearing; but any who listen now will find a flaming fire watching him in ambush", romanUrdu: "Aur yeh ke pehle hum sun-gun lene ke liye aasman mei baithnay ki jagah paa lete thay, magar ab jo chori chupey sunne ke koshish karta hai woh apne liye ghaat mein ek shahabe saaqib (shooting meteors) laga hua paata hai" },
    { number: 10, arabic: "وَأَنَّا لَا نَدْرِىٓ أَشَرٌّ أُرِيدَ بِمَن فِى ٱلْأَرْضِ أَمْ أَرَادَ بِهِمْ رَبُّهُمْ رَشَدًۭا", transliteration: "Waanna la nadree asharrun oreeda biman fee alardi am arada bihim rabbuhum rashadan", transliterationB: "Wa annaa laa nadreee asharrun ureeda biman fil ardi am araada bihim rabbuhum rashadaa", english: "And we understand not whether ill is intended to those on earth, or whether their Lord (really) intends to guide them to right conduct", romanUrdu: "Aur yeh ke hamari samajh mein na aata tha ke aaya zameen walon ke saath koi bura maamla karne ka irada kiya gaya hai ya unka Rubb unhein raah-e-raast dikhana chahta hai" },
    { number: 11, arabic: "وَأَنَّا مِنَّا ٱلصَّٰلِحُونَ وَمِنَّا دُونَ ذَٰلِكَ ۖ كُنَّا طَرَآئِقَ قِدَدًۭا", transliteration: "Waanna minna alssalihoona waminna doona thalika kunna taraiqa qidadan", transliterationB: "Wa annaa minnas saalihoona wa minnaa doona zaalika kunnaa taraaa'ilqa qidadaa", english: "There are among us some that are righteous, and some the contrary: we follow divergent paths", romanUrdu: "Aur yeh ke hum mein se kuch log saleh (upright) hain aur kuch is se farotar hain, hum mukhtalif tareeqon (ways/factions) mein batey (divided) huey hain" },
    { number: 12, arabic: "وَأَنَّا ظَنَنَّآ أَن لَّن نُّعْجِزَ ٱللَّهَ فِى ٱلْأَرْضِ وَلَن نُّعْجِزَهُۥ هَرَبًۭا", transliteration: "Wanna thananna an lan nuAAjiza Allaha fee alardi walan nuAAjizahu haraban", transliterationB: "Wa annaa zanannaaa al lan nu'jizal laaha fil ardi wa lan nu'jizahoo harabaa", english: "But we think that we can by no means frustrate Allah throughout the earth, nor can we frustrate Him by flight", romanUrdu: "Auy yeh ke hum samajhte thay ke na zameen mein hum Allah ko aajiz (frustrate) kar sakte hain aur na bhaag kar usey hara saktey hain" },
    { number: 13, arabic: "وَأَنَّا لَمَّا سَمِعْنَا ٱلْهُدَىٰٓ ءَامَنَّا بِهِۦ ۖ فَمَن يُؤْمِنۢ بِرَبِّهِۦ فَلَا يَخَافُ بَخْسًۭا وَلَا رَهَقًۭا", transliteration: "Waanna lamma samiAAna alhuda amanna bihi faman yumin birabbihi fala yakhafu bakhsan wala rahaqan", transliterationB: "Wa annaa lammaa sami'nal hudaaa aamannaa bihee famany yu'mim bi rabbihee falaa yakhaafu bakhsanw wa laa rahaqaa", english: "And as for us, since we have listened to the Guidance, we have accepted it: and any who believes in his Lord has no fear, either of a short (account) or of any injustice", romanUrdu: "Aur yeh ke humne jab hidayat ki taleem suni to hum uspar iman le aaye ab jo koi bhi apne Rubb par iman le aayega usey kisi haq-talfi ya zulm ka khauff na hoga" },
    { number: 14, arabic: "وَأَنَّا مِنَّا ٱلْمُسْلِمُونَ وَمِنَّا ٱلْقَٰسِطُونَ ۖ فَمَنْ أَسْلَمَ فَأُو۟لَٰٓئِكَ تَحَرَّوْا۟ رَشَدًۭا", transliteration: "Waanna minna almuslimoona waminna alqasitoona faman aslama faolaika taharraw rashadan", transliterationB: "Wa annaa minnal muslimoona wa minnal qaasitoona faman aslama fa ulaaa'ika taharraw rashadaa", english: "Amongst us are some that submit their wills (to Allah), and some that swerve from justice. Now those who submit their wills - they have sought out (the path) of right conduct", romanUrdu: "Aur yeh ke hum mein se kuch muslim(Allah ke itaat guzar) hain aur kuch haqq se munharif (upright) to jinhon ne Islam (itaat ka raasta) ikhtiyar kar liya unhon ne najaat ki raah dhoond li" },
    { number: 15, arabic: "وَأَمَّا ٱلْقَٰسِطُونَ فَكَانُوا۟ لِجَهَنَّمَ حَطَبًۭا", transliteration: "Waama alqasitoona fakanoo lijahannama hataban", transliterationB: "Wa ammal qaasitoona fa kaanoo li jahannama hatabaa", english: "But those who swerve,- they are (but) fuel for Hell-fire", romanUrdu: "Aur jo haqq se muhnarif hai woh jahannum ka indhan (fuel) banney wala hai" },
    { number: 16, arabic: "وَأَلَّوِ ٱسْتَقَٰمُوا۟ عَلَى ٱلطَّرِيقَةِ لَأَسْقَيْنَٰهُم مَّآءً غَدَقًۭا", transliteration: "Waallawi istaqamoo AAala alttareeqati laasqaynahum maan ghadaqan", transliterationB: "Wa alla wis taqaamoo 'alat tareeqati la asqaynaahum maa'an ghadaqaa", english: "(And Allah's Message is): \"If they (the Pagans) had (only) remained on the (right) Way, We should certainly have bestowed on them Rain in abundance", romanUrdu: "Aur (aey Nabi kaho mujhpar yeh wahee bhi ki gayi hai ke) log agar raah-e-raast par sabit qadami (firmly) se chalte to hum unhein khoob sairaab karte (provide abundant rain)" },
    { number: 17, arabic: "لِّنَفْتِنَهُمْ فِيهِ ۚ وَمَن يُعْرِضْ عَن ذِكْرِ رَبِّهِۦ يَسْلُكْهُ عَذَابًۭا صَعَدًۭا", transliteration: "Linaftinahum feehi waman yuAArid AAan thikri rabbihi yaslukhu AAathaban saAAadan", transliterationB: "Linaftinahum feeh; wa many yu'rid 'an zikri rabbihee yasluk hu 'azaaban sa'adaa", english: "That We might try them by that (means). But if any turns away from the remembrance of his Lord, He will cause him to undergo a severe Penalty", romanUrdu: "Taa-ke is niyamat se unki aazmaish karein aur jo apne Rubb ke zikr se mooh modega uska Rubb usey sakht azaab mein mubtala kardega" },
    { number: 18, arabic: "وَأَنَّ ٱلْمَسَٰجِدَ لِلَّهِ فَلَا تَدْعُوا۟ مَعَ ٱللَّهِ أَحَدًۭا", transliteration: "Waanna almasajida lillahi fala tadAAoo maAAa Allahi ahadan", transliterationB: "Wa annal masaajida lillaahi falaa tad'oo ma'al laahi ahadaa", english: "And the places of worship are for Allah (alone): So invoke not any one along with Allah", romanUrdu: "Aur yeh ke masjidein Allah ke liye hai, lihaza unmein Allah ke saath kisi aur ko na pukaro" },
    { number: 19, arabic: "وَأَنَّهُۥ لَمَّا قَامَ عَبْدُ ٱللَّهِ يَدْعُوهُ كَادُوا۟ يَكُونُونَ عَلَيْهِ لِبَدًۭا", transliteration: "Waannahu lamma qama AAabdu Allahi yadAAoohu kadoo yakoonoona AAalayhi libadan", transliterationB: "Wa annahoo lammaa qaama 'adul laahi yad'oohu kaadoo yakoonoona 'alaihi libadaa", english: "Yet when the Devotee of Allah stands forth to invoke Him, they just make round him a dense crowd", romanUrdu: "Aur yeh ke jab Allah ka banda usko pukarne ke liye khada hua to log uspar toot padne ke liye tayyar ho gaye" },
    { number: 20, arabic: "قُلْ إِنَّمَآ أَدْعُوا۟ رَبِّى وَلَآ أُشْرِكُ بِهِۦٓ أَحَدًۭا", transliteration: "Qul innama adAAoo rabbee wala oshriku bihi ahadan", transliterationB: "Qul innamaaa ad'oo rabbee wa laaa ushriku biheee ahadaa", english: "Say: \"I do no more than invoke my Lord, and I join not with Him any (false god)", romanUrdu: "Aey Nabi ,kaho ke main to apne Rubb ko pukarta hoon aur uske saath kisi ko sharik nahin karta" },
    { number: 21, arabic: "قُلْ إِنِّى لَآ أَمْلِكُ لَكُمْ ضَرًّۭا وَلَا رَشَدًۭا", transliteration: "Qul innee la amliku lakum darran wala rashadan", transliterationB: "Qul innee laaa amliku lakum darranw wa laa rashadaa", english: "Say: \"It is not in my power to cause you harm, or to bring you to right conduct", romanUrdu: "Kaho main tum logon keliye na kisi nuksan ka ikhtiyar rakhta hoon na kisi bhalayi ka" },
    { number: 22, arabic: "قُلْ إِنِّى لَن يُجِيرَنِى مِنَ ٱللَّهِ أَحَدٌۭ وَلَنْ أَجِدَ مِن دُونِهِۦ مُلْتَحَدًا", transliteration: "Qul innee lan yujeeranee mina Allahi ahadun walan ajida min doonihi multahadan", transliterationB: "Qul innee lany yujeeranee minal laahi ahad, wa lan ajida min doonihee multahadaa", english: "Say: \"No one can deliver me from Allah (If I were to disobey Him), nor should I find refuge except in Him", romanUrdu: "Kaho mujhey Allah ki giraft se koi nahin bacha sakta aur na main uske daaman ke siwa koi jaye panaah (refuge) paa sakta hoon" },
    { number: 23, arabic: "إِلَّا بَلَٰغًۭا مِّنَ ٱللَّهِ وَرِسَٰلَٰتِهِۦ ۚ وَمَن يَعْصِ ٱللَّهَ وَرَسُولَهُۥ فَإِنَّ لَهُۥ نَارَ جَهَنَّمَ خَٰلِدِينَ فِيهَآ أَبَدًا", transliteration: "Illa balaghan mina Allahi warisalatihi waman yaAAsi Allaha warasoolahu fainna lahu nara jahannama khalideena feeha abadan", transliterationB: "Illaa balaagham minal laahi wa risaalaatih; wa many ya'sil laaha wa rasoolahoo fa inna lahoo naara jahannama khaalideena feehaaa abadaa", english: "Unless I proclaim what I receive from Allah and His Messages: for any that disobey Allah and His Messenger,- for them is Hell: they shall dwell therein for ever", romanUrdu: "Mera kaam iske siwa kuch nahin hai ke Allah ki baat aur uske paighamaat pahuncha doon. Ab jo bhi Allah aur uske Rasool ki baat na maanega uske liye jahannum ki aag hai aur aisey log usmein hamesha rahenge" },
    { number: 24, arabic: "حَتَّىٰٓ إِذَا رَأَوْا۟ مَا يُوعَدُونَ فَسَيَعْلَمُونَ مَنْ أَضْعَفُ نَاصِرًۭا وَأَقَلُّ عَدَدًۭا", transliteration: "Hatta itha raaw ma yooAAadoona fasayaAAlamoona man adAAafu nasiran waaqallu AAadadan", transliterationB: "Hattaaa izaa ra aw maa yoo'adoona fasaya'lamoona man ad'afu naasiranw wa aqallu 'adadaa", english: "At length, when they see (with their own eyes) that which they are promised,- then will they know who it is that is weakest in (his) helper and least important in point of numbers", romanUrdu: "(Yeh log apni is rawish se baaz na aayenge) yahan tak ke jab us cheez ko dekh lenge jiska inse waada kiya ja raha hai to inhein maloom ho jayega ke kiske madadgaar kamzoar hain aur kiska jattha (group) taadad mein kam hai" },
    { number: 25, arabic: "قُلْ إِنْ أَدْرِىٓ أَقَرِيبٌۭ مَّا تُوعَدُونَ أَمْ يَجْعَلُ لَهُۥ رَبِّىٓ أَمَدًا", transliteration: "Qul in adree aqareebun ma tooAAadoona am yajAAalu lahu rabbee amadan", transliterationB: "Qul in adreee a qareebum maa too'adoona am yaj'alu lahoo rabbeee amadaa", english: "Say: \"I know not whether the (Punishment) which ye are promised is near, or whether my Lord will appoint for it a distant term", romanUrdu: "Kaho, main nahin jaanta ke jis cheez ka waada tumse kiya ja raha hai woh qareeb hai ya mera Rubb uske liye koi lambi muddat muqarrar famata hai" },
    { number: 26, arabic: "عَٰلِمُ ٱلْغَيْبِ فَلَا يُظْهِرُ عَلَىٰ غَيْبِهِۦٓ أَحَدًا", transliteration: "AAalimu alghaybi fala yuthhiru AAala ghaybihi ahadan", transliterationB: "Aalimul ghaibi falaa yuzhiru alaa ghaibiheee ahadaa", english: "He (alone) knows the Unseen, nor does He make any one acquainted with His Mysteries", romanUrdu: "Woh aalimul gaib hai , apne gaib par kisi ko muttala (reveal/disclose) nahin karta" },
    { number: 27, arabic: "إِلَّا مَنِ ٱرْتَضَىٰ مِن رَّسُولٍۢ فَإِنَّهُۥ يَسْلُكُ مِنۢ بَيْنِ يَدَيْهِ وَمِنْ خَلْفِهِۦ رَصَدًۭا", transliteration: "Illa mani irtada min rasoolin fainnahu yasluku min bayni yadayhi wamin khalfihi rasadan", transliterationB: "Illaa manir tadaa mir rasoolin fa innahoo yasluku mim baini yadihi wa min khalfihee rasadaa", english: "Except a messenger whom He has chosen: and then He makes a band of watchers march before him and behind him", romanUrdu: "Siwai us Rasool ke jisey usne (gaib ka koi ilm dene ke liye) pasand karliya ho, to uske aagey aur pichey woh muhafiz (guards) laga deta hai" },
    { number: 28, arabic: "لِّيَعْلَمَ أَن قَدْ أَبْلَغُوا۟ رِسَٰلَٰتِ رَبِّهِمْ وَأَحَاطَ بِمَا لَدَيْهِمْ وَأَحْصَىٰ كُلَّ شَىْءٍ عَدَدًۢا", transliteration: "LiyaAAlama an qad ablaghoo risalati rabbihim waahata bima ladayhim waahsa kulla shayin AAadadan", transliterationB: "Liya'lama an qad ablaghoo risaalaati rabbihim wa ahaata bima ladihim wa ahsaa kulla shai'in 'adadaa", english: "That He may know that they have (truly) brought and delivered the Messages of their Lord: and He surrounds (all the mysteries) that are with them, and takes account of every single thing", romanUrdu: "Taa-ke woh jaan le ke unhon ne apne Rubb ke paighamaat pahuncha diye, aur woh unke poorey maahol ka ihata (encompass) kiye huey hai aur ek ek cheez ko usne gin rakkha hai" }
  ]
};
